// ─── CARD CLASS ───────────────────────────────────────────────────────────────
class TvMediaCard extends HTMLElement {
  constructor() {
    super();
    this.attachShadow({ mode: 'open' });
    this._cfg          = {};
    this._lang         = 'en';
    this._hass         = null;
    this._raf          = null;
    this._hassInited   = false;
    this._editMode     = false;
  }

  setConfig(config) {
    if (!config.entity) throw new Error('[tv-media-card] "entity" is required');
    this._cfg = {
      entity:            config.entity,
      cast_entity:       config.cast_entity || null,
      name:              config.name  || null,
      brand:             config.brand || '',
      language:          config.language || 'en',
      apps:              config.apps  || null,
      volume_steps:      parseInt(config.volume_steps, 10) || 0,
    };
    this._lang = this._cfg.language;
    this._render();
  }

  set hass(hass) {
    this._hass = hass;
    this._hassInited = true;
    this._updateCard();
  }

  disconnectedCallback() {
    this._stopBentoSwap();
    if (this._raf) {
      cancelAnimationFrame(this._raf);
      this._raf = null;
    }
  }

  getCardSize() { return 6; }

  // ── helpers ─────────────────────────────────────────────────────────────────
  _t(k)  { return (TV_I18N[this._lang] || TV_I18N.en)[k] || k; }
  _$(id) { return this.shadowRoot.getElementById(id); }

  _callMedia(svc, data = {}) {
    if (!this._hass) return;
    this._hass.callService('media_player', svc, { entity_id: this._cfg.entity, ...data });
  }

  _callCast(svc, data = {}) {
    if (!this._hass) return;
    const target = this._cfg.cast_entity || this._cfg.entity;
    this._hass.callService('media_player', svc, { entity_id: target, ...data });
  }

  _fmt(sec) {
    if (!sec || isNaN(sec) || sec < 0) return '0:00';
    const s = Math.floor(sec), h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), ss = s % 60;
    return h ? `${h}:${String(m).padStart(2,'0')}:${String(ss).padStart(2,'0')}` : `${m}:${String(ss).padStart(2,'0')}`;
  }

  _domainEntities(domain) {
    if (!this._hass) return [];
    return Object.keys(this._hass.states)
      .filter(e => e.startsWith(domain + '.'))
      .sort((a, b) => {
        const na = this._hass.states[a]?.attributes?.friendly_name || a;
        const nb = this._hass.states[b]?.attributes?.friendly_name || b;
        return na.localeCompare(nb);
      });
  }

  _buildOpts(entities, current, withNone = false) {
    let html = withNone ? `<option value="">${this._t('none')}</option>` : '';
    for (const eid of entities) {
      const fname = this._hass?.states[eid]?.attributes?.friendly_name;
      const label = fname ? `${fname} (${eid})` : eid;
      html += `<option value="${eid}"${eid === current ? ' selected' : ''}>${label}</option>`;
    }
    return html;
  }

  _getApps() {
    // Try card config first, then fallback to defaults
    // NOTE: localStorage removed — HA cards should not rely on it
    if (this._savedApps) return [...this._savedApps];
    return this._cfg.apps ? [...this._cfg.apps] : [...DEFAULT_APPS];
  }

  _saveApps(apps) {
    // Store in memory (persists for this card instance)
    this._savedApps = apps;
  }

  // ── render (once) ────────────────────────────────────────────────────────────
  _render() {
    const c = this._cfg;
    const apps = this._getApps();

    this.shadowRoot.innerHTML = `
      <style>${TV_CSS}</style>

      <div class="card">
        <div class="card-bg" id="cardBg"></div>

        <div class="hdr">
          <div>
            <div class="room" id="room">${c.name || c.entity}</div>
            <div class="badge">
              <div class="dot off" id="dot"></div>
              <span id="stTxt">${this._t('off')}</span>
            </div>
          </div>
          <div class="hdr-right">
            <button class="mute-btn" id="btnMute" aria-label="Mute">
              <svg id="muteIc" viewBox="0 0 24 24" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/>
                <path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>
              </svg>
            </button>
            <button class="gear-btn" id="btnGear" aria-label="Settings">
              <svg viewBox="0 0 24 24" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                <circle cx="12" cy="12" r="3"/>
                <path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/>
              </svg>
            </button>
            <button class="pwr dim" id="pwr" aria-label="Power">
              <svg viewBox="0 0 24 24" fill="none" stroke-width="2" stroke-linecap="round">
                <path d="M18.36 6.64a9 9 0 1 1-12.73 0"/>
                <line x1="12" y1="2" x2="12" y2="12"/>
              </svg>
            </button>
          </div>
        </div>

        <div class="tv-outer">
          <div class="tv-click" id="tvClick">
            <div class="tv-body">
              <div class="screen" id="scr">
                <div class="scr-poster" id="scrPoster"></div>
                <div class="scr-app-badge" id="scrAppBadge"></div>
                <div class="scr-bg" id="scrBg" style="opacity:.04">
                  <div class="logo-wrap" id="logoWrap" style="display:none"></div>
                  <div id="offMsg" style="display:flex">
                    <span class="off-msg">${this._t('standby')}</span>
                  </div>
                  <div id="homeWrap" style="display:none" class="bento-home">
                    ${_buildBentoHTML(apps)}
                  </div>
                </div>
                <div class="hint">
                  <svg viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/></svg>
                  <span>${this._t('launchApp')}</span>
                </div>
              </div>
              <div class="bezel">
                <span class="tv-brand" id="brand">${(c.brand || '').toUpperCase()}</span>
                <div class="led off" id="led"></div>
              </div>
            </div>
            <div class="stand"><div class="neck"></div><div class="foot"></div></div>
          </div>
        </div>

        <div class="np">
          <div class="np-app"   id="npApp"></div>
          <div class="np-title" id="npTitle">—</div>
          <div class="np-sub"   id="npSub">${this._t('nowPlaying')}</div>
        </div>

        <div class="prog">
          <div class="times"><span id="cur">0:00</span><span id="tot">0:00</span></div>
          <div class="pbar" id="pbar">
            <div class="pfill" id="pfill"><div class="pthumb"></div></div>
          </div>
        </div>

        <div class="ctrls">
          <button class="btn sm" id="btnPrev" aria-label="Previous">
            <svg viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,.65)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <polygon points="19 20 9 12 19 4 19 20"/><line x1="5" y1="19" x2="5" y2="5"/>
            </svg>
          </button>
          <button class="btn lg" id="btnPlay" aria-label="Play/Pause">
            <svg id="icPlay"  viewBox="0 0 24 24" fill="white" style="display:none"><polygon points="5 3 19 12 5 21 5 3"/></svg>
            <svg id="icPause" viewBox="0 0 24 24" fill="white"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>
          </button>
          <button class="btn sm" id="btnNext" aria-label="Next">
            <svg viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,.65)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <polygon points="5 4 15 12 5 20 5 4"/><line x1="19" y1="5" x2="19" y2="19"/>
            </svg>
          </button>
        </div>

        <div class="divider"></div>

        <div class="vol">
          <div class="vol-ic" id="volIc" role="button" aria-label="Mute">
            <svg id="volSvg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/>
              <path d="M19.07 4.93a10 10 0 0 1 0 14.14"/>
              <path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>
            </svg>
          </div>
          <button class="vol-step" id="volDown" aria-label="Volume Down">−</button>
          <div class="vbar" id="vbar"><div class="vfill" id="vfill"><div class="vthumb"></div></div></div>
          <button class="vol-step" id="volUp" aria-label="Volume Up">+</button>
          <div class="vol-pct" id="volPct">0%</div>
        </div>

      </div>

      <!-- Settings overlay -->
      <div class="overlay" id="overlay">
        <div class="modal">
          <div class="m-head">
            <div class="m-title">${GEAR_SVG}<span>${this._t('cardSettings')}</span></div>
            <button class="m-close" id="mClose" aria-label="Close">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round">
                <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
              </svg>
            </button>
          </div>
          <div class="m-body">
            <div class="s-sec">${this._t('general')}</div>
            <div class="s-row">
              <div class="s-lbl">${this._t('roomName')}</div>
              <input class="s-inp" id="iName" type="text" value="${c.name || ''}" placeholder="${c.entity}">
            </div>
            <div class="s-row">
              <div class="s-lbl">${this._t('brand')}</div>
              <input class="s-inp" id="iBrand" type="text" value="${c.brand || ''}" placeholder="SAMSUNG / LG / SONY…">
            </div>
            <div class="s-row">
              <div class="s-lbl">${this._t('entity')}</div>
              <select class="s-sel" id="iEntity"><option value="${c.entity}">${c.entity}</option></select>
            </div>
            <div class="s-row">
              <div class="s-lbl">${this._t('castEntity')}</div>
              <select class="s-sel" id="iCastEntity"><option value="">${this._t('none')}</option></select>
            </div>
            <div class="s-sec">${this._t('appearance')}</div>
            <div class="s-row">
              <div class="s-lbl">${this._t('volumeSteps')}</div>
              <select class="s-sel" id="iVolSteps">
                <option value="0">${this._t('volOpt0')}</option>
                <option value="15">${this._t('volOpt15')}</option>
                <option value="25">${this._t('volOpt25')}</option>
                <option value="50">${this._t('volOpt50')}</option>
                <option value="100">${this._t('volOpt100')}</option>
              </select>
              <div style="font-size:10px;color:rgba(255,255,255,.25);margin-top:2px;">${this._t('volumeStepsHint')}</div>
            </div>
            <div class="s-row">
              <div class="s-lbl">${this._t('lang')}</div>
              <select class="s-sel" id="iLang">
                <option value="en">English</option>
                <option value="ro">Română</option>
                <option value="de">Deutsch</option>
                <option value="fr">Français</option>
                <option value="es">Español</option>
                <option value="it">Italiano</option>
                <option value="pl">Polski</option>
                <option value="hu">Magyar</option>
                <option value="nl">Nederlands</option>
                <option value="pt">Português</option>
                <option value="cs">Čeština</option>
                <option value="sk">Slovenčina</option>
              </select>
            </div>
            <button class="s-apply" id="btnApply">${this._t('apply')}</button>
          </div>
        </div>
      </div>

      <!-- App launcher overlay -->
      <div class="app-overlay" id="appOverlay">
        <div class="app-modal">
          <div class="app-head">
            <div class="app-head-title">${this._t('launchApp')}</div>
            <div style="display:flex;gap:6px;align-items:center;">
              <button class="app-edit-btn" id="btnEditApps">${this._t('edit')}</button>
              <button class="app-close" id="appClose" aria-label="Close">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round">
                  <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
                </svg>
              </button>
            </div>
          </div>
          <div class="app-grid" id="appGrid"></div>
        </div>
      </div>
    `;

    this._$('iLang').value = this._lang;
    this._bindEvents();
  }

  // ── events ──────────────────────────────────────────────────────────────────
  _bindEvents() {
    this._$('pwr').addEventListener('click', () => {
      if (!this._hass) return;
      const stObj  = this._hass.states[this._cfg.entity];
      const s      = stObj?.state;
      const attr   = stObj?.attributes || {};
      const assumed    = attr.assumed_state === true;
      const hasLive    = !!(attr.app_id || attr.app_name || attr.media_title);
      const currentlyOn = (assumed && hasLive) ? true : (s !== 'off' && s !== 'unavailable');
      this._callMedia(currentlyOn ? 'turn_off' : 'turn_on');
    });

    this._$('btnPlay').addEventListener('click', () => {
      const castEid = this._cfg.cast_entity || this._cfg.entity;
      const s = this._hass?.states[castEid]?.state;
      this._callCast(s === 'playing' ? 'media_pause' : 'media_play');
    });
    this._$('btnPrev').addEventListener('click', () => this._callCast('media_previous_track'));
    this._$('btnNext').addEventListener('click', () => this._callCast('media_next_track'));

    this._$('pbar').addEventListener('click', e => {
      const r   = e.currentTarget.getBoundingClientRect();
      const pct = Math.max(0, Math.min(1, (e.clientX - r.left) / r.width));
      const castEid = this._cfg.cast_entity || this._cfg.entity;
      const dur = this._hass?.states[castEid]?.attributes?.media_duration || 0;
      if (dur > 0) this._callCast('media_seek', { seek_position: +(pct * dur).toFixed(1) });
    });

    this._$('vbar').addEventListener('click', e => {
      // Only use volume_set if the entity supports it
      const features = this._hass?.states[this._cfg.entity]?.attributes?.supported_features || 0;
      const supportsVolumeSet = !!(features & 4); // VOLUME_SET = 4
      if (!supportsVolumeSet) return; // bar click does nothing if not supported
      const r   = e.currentTarget.getBoundingClientRect();
      let pct = Math.max(0, Math.min(1, (e.clientX - r.left) / r.width));
      const steps = this._cfg.volume_steps;
      if (steps > 0) {
        const step = Math.round(pct * steps);
        pct = step / steps;
      }
      pct = +pct.toFixed(2);
      this._callMedia('volume_set', { volume_level: pct });
    });

    this._$('volDown').addEventListener('click', () => this._callMedia('volume_down'));
    this._$('volUp').addEventListener('click', () => this._callMedia('volume_up'));

    this._$('btnMute').addEventListener('click', () => {
      const muted = this._hass?.states[this._cfg.entity]?.attributes?.is_volume_muted ?? false;
      this._callMedia('volume_mute', { is_volume_muted: !muted });
    });

    this._$('volIc').addEventListener('click', () => {
      const muted = this._hass?.states[this._cfg.entity]?.attributes?.is_volume_muted ?? false;
      this._callMedia('volume_mute', { is_volume_muted: !muted });
    });

    this._$('btnGear').addEventListener('click',  () => this._openSettings());
    this._$('mClose').addEventListener('click',   () => this._closeSettings());
    this._$('overlay').addEventListener('click', e => { if (e.target === this._$('overlay')) this._closeSettings(); });

    this._$('tvClick').addEventListener('click',   () => this._openApps());

    this._$('btnApply').addEventListener('click', () => {
      const name   = this._$('iName').value.trim();
      const brand  = this._$('iBrand').value.trim();
      const entity = this._$('iEntity').value;
      const castEntity = this._$('iCastEntity').value || null;
      const lang   = this._$('iLang').value;
      const volSteps = parseInt(this._$('iVolSteps').value, 10) || 0;

      // Update internal config — always set, even if empty
      this._cfg.name = name || null;
      this._cfg.brand = brand || '';
      this._cfg.entity = entity;
      this._cfg.cast_entity = castEntity;
      this._lang = lang;
      this._cfg.language = lang;
      this._cfg.volume_steps = volSteps;

      // Update UI immediately
      this._$('room').textContent = name || this._hass?.states[entity]?.attributes?.friendly_name || entity;
      this._$('brand').textContent = (brand || '').toUpperCase();

      // Persist to YAML — fire config-changed event so HA saves it
      const newConfig = { type: 'custom:tv-media-card', entity: entity };
      if (castEntity)            newConfig.cast_entity  = castEntity;
      if (name)                  newConfig.name         = name;
      if (brand)                 newConfig.brand        = brand;
      if (lang && lang !== 'en') newConfig.language     = lang;
      if (volSteps)              newConfig.volume_steps = volSteps;
      if (this._cfg.apps)        newConfig.apps         = this._cfg.apps;
      this.dispatchEvent(new CustomEvent('config-changed', { detail: { config: newConfig }, bubbles: true, composed: true }));

      this._closeSettings();
      this._updateCard();
    });
  }

  _openApps() {
    this._editMode = false;
    this._renderAppGrid();
    this._$('appOverlay').classList.add('open');

    this._$('btnEditApps').onclick = () => {
      this._editMode = !this._editMode;
      this._$('btnEditApps').classList.toggle('active', this._editMode);
      this._$('btnEditApps').textContent = this._editMode ? this._t('done') : this._t('edit');
      this._renderAppGrid();
    };

    this._$('appClose').onclick  = () => this._closeApps();
    this._$('appOverlay').onclick = e => { if (e.target === this._$('appOverlay')) this._closeApps(); };
  }

  _renderAppGrid() {
    const currentAppId = this._hass?.states[this._cfg.entity]?.attributes?.app_id || '';
    const apps = this._getApps();
    const grid = this._$('appGrid');
    const editMode = this._editMode;

    let tilesHtml = apps.map((app, i) => {
      const logo = tvGetLogo(app.id);
      const isActive = currentAppId === app.id;
      const hue = ((app.name.charCodeAt(0) || 0) * 47 + (app.name.charCodeAt(1) || 0) * 13) % 360;
      const logoHtml = logo
        ? `<div class="app-logo">${logo}</div>`
        : `<div class="app-logo"><div class="app-logo-fallback" style="background:hsl(${hue},55%,35%)">${app.name[0].toUpperCase()}</div></div>`;
      return `<div class="app-item${isActive ? ' active-app' : ''}" data-idx="${i}" data-app-id="${app.id}" draggable="${editMode}">
        <button class="app-del" data-idx="${i}" title="Remove">&times;</button>
        ${logoHtml}
        <div class="app-name">${app.name}</div>
      </div>`;
    }).join('');

    tilesHtml += `<div class="app-item app-add" id="btnAddApp" title="${this._t('add')}">+<div class="app-name">${this._t('add')}</div></div>`;
    tilesHtml += `<div class="add-form" id="addForm">
      <input class="add-inp" id="addName" type="text" placeholder="${this._t('appName')} (ex: YouTube)">
      <input class="add-inp" id="addId" type="text" placeholder="${this._t('packageId')} (ex: com.google.android.youtube.tv)">
      <div class="add-row">
        <button class="add-save" id="addSave">${this._t('add')}</button>
        <button class="add-cancel" id="addCancel">${this._t('cancel')}</button>
      </div>
    </div>`;

    grid.innerHTML = tilesHtml;
    grid.classList.toggle('edit-mode', editMode);

    grid.querySelectorAll('.app-item:not(.app-add)').forEach(el => {
      el.addEventListener('click', () => {
        if (this._editMode) return;
        this._launchApp(el.dataset.appId);
        this._closeApps();
      });
    });

    grid.querySelectorAll('.app-del').forEach(btn => {
      btn.addEventListener('click', e => {
        e.stopPropagation();
        const idx = +btn.dataset.idx;
        const apps = this._getApps();
        apps.splice(idx, 1);
        this._saveApps(apps);
        this._renderAppGrid();
      });
    });

    const addBtn = this._$('btnAddApp');
    if (addBtn) {
      addBtn.addEventListener('click', () => {
        const form = this._$('addForm');
        if (form) { form.classList.add('open'); this._$('addName')?.focus(); }
      });
    }

    const saveBtn = this._$('addSave');
    if (saveBtn) {
      saveBtn.addEventListener('click', () => {
        const name = this._$('addName')?.value?.trim();
        const id   = this._$('addId')?.value?.trim();
        if (!name || !id) return;
        const apps = this._getApps();
        apps.push({ name, id });
        this._saveApps(apps);
        this._renderAppGrid();
      });
    }

    const cancelBtn = this._$('addCancel');
    if (cancelBtn) {
      cancelBtn.addEventListener('click', () => {
        this._$('addForm')?.classList.remove('open');
      });
    }

    if (editMode) this._bindDrag(grid);
  }

  _bindDrag(grid) {
    let dragIdx = null;
    grid.querySelectorAll('.app-item[draggable="true"]').forEach(el => {
      el.addEventListener('dragstart', e => {
        dragIdx = +el.dataset.idx;
        el.style.opacity = '.4';
        e.dataTransfer.effectAllowed = 'move';
      });
      el.addEventListener('dragend',  () => { el.style.opacity = ''; dragIdx = null; });
      el.addEventListener('dragover', e => {
        e.preventDefault();
        if (dragIdx === null || +el.dataset.idx === dragIdx) return;
        const apps = this._getApps();
        const moved = apps.splice(dragIdx, 1)[0];
        const targetIdx = +el.dataset.idx;
        apps.splice(targetIdx, 0, moved);
        dragIdx = targetIdx;
        this._saveApps(apps);
        this._renderAppGrid();
      });
    });
  }

  _closeApps() {
    this._$('appOverlay').classList.remove('open');
    this._editMode = false;
  }

  _launchApp(appId) {
    if (!this._hass || !appId) return;
    this._hass.callService('media_player', 'play_media', {
      entity_id: this._cfg.entity,
      media_content_type: 'app',
      media_content_id: appId,
    });
  }

  _openSettings() {
    const mpEntities = this._domainEntities('media_player');
    this._$('iEntity').innerHTML = this._buildOpts(mpEntities, this._cfg.entity, false);
    this._$('iCastEntity').innerHTML = this._buildOpts(mpEntities, this._cfg.cast_entity || '', true);
    this._$('iName').value  = this._cfg.name  || '';
    this._$('iBrand').value = this._cfg.brand || '';
    this._$('iLang').value  = this._lang;
    this._$('iVolSteps').value = String(this._cfg.volume_steps || 0);
    this._$('overlay').classList.add('open');
  }

  _closeSettings() {
    this._$('overlay').classList.remove('open');
  }

  // ── state → DOM ─────────────────────────────────────────────────────────────
  _updateCard() {
    if (!this._hass) return;
    const sr = this.shadowRoot;
    if (!sr || !sr.getElementById('dot')) return;

    const stObj = this._hass.states[this._cfg.entity];
    if (!stObj) return;

    const s          = stObj.state;
    const attr       = stObj.attributes || {};

    // Cast entity for media info (title, progress, play state)
    const castEid    = this._cfg.cast_entity;
    const castObj    = castEid ? this._hass.states[castEid] : null;
    const castState  = castObj?.state || '';
    const castAttr   = castObj?.attributes || {};

    const assumed    = attr.assumed_state === true;
    const hasLiveData = !!(attr.app_id || attr.app_name || attr.media_title || castAttr.media_title);
    const isOn       = (assumed && hasLiveData)
                       ? true
                       : s !== 'off' && s !== 'unavailable';

    // Use cast state for playing detection if available
    const isPlaying  = castObj ? castState === 'playing' : s === 'playing';
    const isPaused   = castObj ? castState === 'paused'  : s === 'paused';

    sr.getElementById('room').textContent =
      this._cfg.name || attr.friendly_name || this._cfg.entity;

    sr.getElementById('dot').classList.toggle('off', !isOn);
    const stMap = { on: this._t('on'), playing: this._t('on'), paused: this._t('on'), idle: this._t('idle'), off: this._t('off'), unavailable: this._t('unavailable') };
    sr.getElementById('stTxt').textContent = stMap[s] ?? (isOn ? this._t('on') : this._t('off'));

    sr.getElementById('pwr').classList.toggle('dim', !isOn);
    sr.getElementById('scr').classList.toggle('on', isOn);
    sr.getElementById('scrBg').style.opacity = isOn ? '1' : '.04';
    sr.getElementById('led').classList.toggle('off', !isOn);

    // App logo + name — prefer main entity for app_id (remote knows the app)
    const rawApp  = (attr.app_id || attr.app_name || castAttr.app_name || attr.source || '').trim();
    const appName = _isSystemString(rawApp) ? '' : rawApp;
    // Try logo from app_id first, then app_name (AndroidNativeApp won't match, but "Plex" will)
    const logo    = tvGetLogo(rawApp) || tvGetLogo(attr.app_name || '') || tvGetLogo(castAttr.app_name || '');
    const showLogo = isOn && s !== 'idle' && !!logo;

    // Entity picture (media artwork) — prefer HA proxy paths (no CORS issues)
    // HA can store entity_picture at state level OR in attributes
    const _pic = (obj) => obj?.attributes?.entity_picture_local || obj?.attributes?.entity_picture || '';
    
    // Try cast entity first, then main entity
    let entityPic = _pic(castObj) || _pic(stObj);
    
    // If still no picture, scan for a related media_player entity that has one
    // (e.g. Plex creates a separate entity with the artwork)
    if (!entityPic && this._hass) {
      const mediaTitle = castAttr.media_title || attr.media_title || '';
      const currentApp = (attr.app_name || '').toLowerCase();
      let fallbackPic = '';
      for (const eid of Object.keys(this._hass.states)) {
        if (!eid.startsWith('media_player.')) continue;
        if (eid === this._cfg.entity || eid === this._cfg.cast_entity) continue;
        const st = this._hass.states[eid];
        if (st.state !== 'playing' && st.state !== 'paused') continue;
        const pic = st.attributes?.entity_picture_local || st.attributes?.entity_picture;
        if (!pic) continue;
        const stTitle = st.attributes?.media_title || '';
        const stApp = (st.attributes?.app_name || '').toLowerCase();
        // Strong match: same media title
        if (mediaTitle && stTitle && mediaTitle === stTitle) {
          entityPic = pic;
          break;
        }
        // Medium match: same app name
        if (currentApp && stApp && currentApp === stApp) {
          entityPic = pic;
          break;
        }
        // Weak match: entity id contains the app name (e.g. media_player.plex_...)
        if (currentApp && eid.toLowerCase().includes(currentApp)) {
          entityPic = pic;
          break;
        }
        // Fallback: any playing entity with a picture
        if (!fallbackPic) fallbackPic = pic;
      }
      if (!entityPic) entityPic = fallbackPic;
    }
    
    const hasPoster = isOn && !!entityPic && (isPlaying || isPaused);

    // DEBUG: dump ALL media_player entities and their picture attributes
    if (this._hass && !this._debugDumped) {
      this._debugDumped = true;
      const dump = {};
      for (const eid of Object.keys(this._hass.states)) {
        if (!eid.startsWith('media_player.')) continue;
        const st = this._hass.states[eid];
        const a = st.attributes || {};
        dump[eid] = {
          state: st.state,
          entity_picture_local: a.entity_picture_local || null,
          entity_picture: a.entity_picture || null,
          media_title: a.media_title || null,
          app_name: a.app_name || null,
          app_id: a.app_id || null,
        };
      }
      console.log('[tv-media-card] ALL media_players:', JSON.stringify(dump, null, 2));
    }

    console.log('[tv-media-card] DEBUG poster:', {
      state: s, isOn, isPlaying, isPaused,
      entityPic: entityPic || '(none)',
      hasPoster
    });

    // Background blur image on the card
    const cardBg = sr.getElementById('cardBg');
    if (hasPoster) {
      cardBg.style.backgroundImage = `url("${entityPic}")`;
      cardBg.classList.add('active');
    } else {
      cardBg.classList.remove('active');
    }

    // Screen poster (artwork on TV screen)
    const scrPoster = sr.getElementById('scrPoster');
    if (hasPoster) {
      scrPoster.style.backgroundImage = `url("${entityPic}")`;
      scrPoster.classList.add('active');
    } else {
      scrPoster.classList.remove('active');
    }

    // App badge (small logo in top-right corner of screen)
    const scrAppBadge = sr.getElementById('scrAppBadge');
    if (hasPoster && logo) {
      scrAppBadge.innerHTML = logo;
      scrAppBadge.classList.add('active');
    } else {
      scrAppBadge.classList.remove('active');
    }

    // Full-screen logo only when no poster available
    const showFullLogo = showLogo && !hasPoster;
    sr.getElementById('logoWrap').style.display = showFullLogo ? 'flex' : 'none';
    sr.getElementById('offMsg').style.display   = isOn     ? 'none' : 'flex';
    sr.getElementById('homeWrap').style.display = (isOn && !showFullLogo && !hasPoster) ? 'grid' : 'none';
    if (showFullLogo) sr.getElementById('logoWrap').innerHTML = logo;

    const friendlyApp = attr.app_name && !_isSystemString(attr.app_name) ? attr.app_name : '';
    sr.getElementById('npApp').textContent   = (showLogo || hasPoster) ? (friendlyApp || appName).toUpperCase() : '';

    // Media title — prefer cast entity (it has the actual track/video title)
    const mediaTitle = castAttr.media_title || attr.media_title || '';
    const mediaArtist = castAttr.media_artist || attr.media_artist || '';
    const displayTitle = mediaTitle || (s === 'idle' ? this._t('idle') : '—');
    sr.getElementById('npTitle').textContent = displayTitle;
    sr.getElementById('npSub').textContent   = mediaArtist || this._t('nowPlaying');

    sr.getElementById('icPlay').style.display  = isPlaying ? 'none'  : 'block';
    sr.getElementById('icPause').style.display = isPlaying ? 'block' : 'none';

    // Progress — from cast entity if available
    cancelAnimationFrame(this._raf);
    const mAttr    = castObj ? castAttr : attr;
    const duration = mAttr.media_duration || 0;
    sr.getElementById('tot').textContent = this._fmt(duration);

    if (isPlaying && duration > 0) {
      const snap = mAttr.media_position_updated_at ? (mAttr.media_position || 0) : 0;
      const ref  = mAttr.media_position_updated_at
        ? new Date(mAttr.media_position_updated_at).getTime()
        : Date.now();
      const tick = () => {
        const el = sr.getElementById('pfill');
        const ce = sr.getElementById('cur');
        if (!el) return;
        const pos = Math.min(snap + (Date.now() - ref) / 1000, duration);
        el.style.transition = 'none';
        el.style.width      = (pos / duration * 100).toFixed(2) + '%';
        if (ce) ce.textContent = this._fmt(pos);
        this._raf = requestAnimationFrame(tick);
      };
      this._raf = requestAnimationFrame(tick);
    } else {
      const pos = mAttr.media_position || 0;
      const el  = sr.getElementById('pfill');
      if (el) { el.style.transition = 'width .5s linear'; el.style.width = duration > 0 ? (pos / duration * 100).toFixed(2) + '%' : '0%'; }
      sr.getElementById('cur').textContent = this._fmt(pos);
    }

    // Volume
    const vol    = attr.volume_level    ?? 0;
    const muted  = attr.is_volume_muted ?? false;
    const steps  = this._cfg.volume_steps;
    sr.getElementById('vfill').style.width  = (vol * 100).toFixed(1) + '%';

    if (muted) {
      sr.getElementById('volPct').textContent = '🔇';
    } else if (steps > 0) {
      const step = Math.round(vol * steps);
      sr.getElementById('volPct').textContent = step + '/' + steps;
    } else {
      sr.getElementById('volPct').textContent = Math.round(vol * 100) + '%';
    }

    const effVol = muted ? 0 : vol;
    const svg = sr.getElementById('volSvg');
    if (effVol === 0) {
      svg.innerHTML = `<polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/>`;
    } else if (effVol < 0.5) {
      svg.innerHTML = `<polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>`;
    } else {
      svg.innerHTML = `<polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>`;
    }

    const muteIc = sr.getElementById('muteIc');
    const muteBtn = sr.getElementById('btnMute');
    if (muteIc && muteBtn) {
      muteBtn.classList.toggle('muted', muted);
      muteIc.innerHTML = muted
        ? `<polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/>`
        : `<polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>`;
    }

    // Start/stop bento tile swap animation
    if (isOn && !showLogo) {
      this._startBentoSwap();
    } else {
      this._stopBentoSwap();
    }
  }

  _startBentoSwap() {
    if (this._bentoInterval) return;
    this._bentoInterval = setInterval(() => {
      const sr = this.shadowRoot;
      if (!sr) return;
      const tiles = sr.querySelectorAll('.bento-tile');
      if (tiles.length < 4) return;

      // Pick 2 random different tiles — any tile, including large ones
      const a = Math.floor(Math.random() * tiles.length);
      let b = a;
      let tries = 0;
      while (b === a && tries++ < 20) b = Math.floor(Math.random() * tiles.length);
      if (a === b) return;

      const tA = tiles[a], tB = tiles[b];

      // Phase 1: both fade out slowly
      tA.classList.add('bt-out');
      tB.classList.add('bt-out');

      // Phase 2: swap content at midpoint (when faded out)
      setTimeout(() => {
        const tmpHtml = tA.innerHTML;
        const tmpBg = tA.style.background;
        const tmpBorder = tA.style.border;
        tA.innerHTML = tB.innerHTML;
        tA.style.background = tB.style.background;
        tA.style.border = tB.style.border;
        tB.innerHTML = tmpHtml;
        tB.style.background = tmpBg;
        tB.style.border = tmpBorder;

        // Phase 3: fade back in
        tA.classList.remove('bt-out');
        tA.classList.add('bt-in');
        tB.classList.remove('bt-out');
        tB.classList.add('bt-in');
      }, 1200);

      // Phase 4: clean up classes
      setTimeout(() => {
        tA.classList.remove('bt-in');
        tB.classList.remove('bt-in');
      }, 2600);
    }, 4000);
  }

  _stopBentoSwap() {
    if (this._bentoInterval) {
      clearInterval(this._bentoInterval);
      this._bentoInterval = null;
    }
  }
}

customElements.define('tv-media-card', TvMediaCard);
